FROM jsonb_to_recordset('[{"id": "cap-109-chinese-015", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「如果我們以人文關懷角度切入，不難發現囤積者的生命都承受著失落與喪\n慟。囤積，其實是一種無法割捨的情感阻礙。只有透過囤積，他們以為自己\n並未失去什麼。所以從這個角度來看，囤積者實際上無法處理的，是關於\n□□。」根據文意脈絡，空格處填入下列何者最恰當？", "options": ["分離", "收納", "時間", "理想"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 15, "raw_text": "15. 「如果我們以人文關懷角度切入，不難發現囤積者的生命都承受著失落與喪\n    慟。囤積，其實是一種無法割捨的情感阻礙。只有透過囤積，他們以為自己\n    並未失去什麼。所以從這個角度來看，囤積者實際上無法處理的，是關於\n    □□。」根據文意脈絡，空格處填入下列何者最恰當？\n    (A)分離   (B)收納   (C)時間  (D)理想\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-016", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "荊州街子葛清，自頸以下，遍刺白居易舍人詩。荊客陳至呼觀之，令\n其自解，背上亦能暗記。反手指其札處，至「不是花中偏愛菊」，則有一人\n持杯臨菊叢。又「黃夾纈林1寒有葉」，則指一樹，樹上掛纈2，纈上花紋極\n細。凡刻三十餘首，體無完膚，陳至贊為「白舍人行詩圖」也。\n根據這段文字，下列關於葛清的敘述，何者正確？", "options": ["刺青內容取自白詩", "獲贈白舍人行詩圖      ", "主動展示身上的圖文     1.黃夾纈林：林木盡成黃色 2.纈：音ㄒㄧㄝˊ，印染花紋的絲織品", "詩句圖文皆刺在背部"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 16, "raw_text": "16.\n        荊州街子葛清，自頸以下，遍刺白居易舍人詩。荊客陳至呼觀之，令\n      其自解，背上亦能暗記。反手指其札處，至「不是花中偏愛菊」，則有一人\n      持杯臨菊叢。又「黃夾纈林1寒有葉」，則指一樹，樹上掛纈2，纈上花紋極\n      細。凡刻三十餘首，體無完膚，陳至贊為「白舍人行詩圖」也。\n      根據這段文字，下列關於葛清的敘述，何者正確？\n      (A)刺青內容取自白詩\n      (B)獲贈白舍人行詩圖      \n      (C)主動展示身上的圖文     1.黃夾纈林：林木盡成黃色\n                       2.纈：音ㄒㄧㄝˊ，印染花紋的絲織品\n      (D)詩句圖文皆刺在背部\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-017", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "小華向精通文字學的爺爺請教「囷」字的涵義，爺爺說：「這個字就是\n稻禾在倉廩中，也就是穀倉的意思，是一個會意字。」小華立刻說：「那麼\n□字也是根據這個原理造出來的囉！」爺爺高興地說：「你能夠舉一反三，\n真是孺子可教也。」\n文中空格處應是下列何者？", "options": ["安", "寄", "宵", "宇"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 17, "raw_text": "17.\n        小華向精通文字學的爺爺請教「囷」字的涵義，爺爺說：「這個字就是\n      稻禾在倉廩中，也就是穀倉的意思，是一個會意字。」小華立刻說：「那麼\n      □字也是根據這個原理造出來的囉！」爺爺高興地說：「你能夠舉一反三，\n      真是孺子可教也。」\n      文中空格處應是下列何者？\n      (A)安   (B)寄    (C)宵   (D)宇\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-018", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「用兵久則驕惰自生，驕惰則未有不敗者。勤字所以醫惰，慎字所以醫驕，二\n字之先，須有一誠字以為本。立意要將此事知得透，辨得穿。精誠所至，金石\n為開，鬼神亦避，此在己之誠也。」根據這段文字，下列敘述何者正確？", "options": ["祭祀鬼神，心誠則靈", "勤慎用兵，以誠為本", "慎可以醫惰，勤可以醫驕", "修身首重勤，次為慎，終為誠"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 18, "raw_text": "18. 「用兵久則驕惰自生，驕惰則未有不敗者。勤字所以醫惰，慎字所以醫驕，二\n    字之先，須有一誠字以為本。立意要將此事知得透，辨得穿。精誠所至，金石\n    為開，鬼神亦避，此在己之誠也。」根據這段文字，下列敘述何者正確？\n    (A)祭祀鬼神，心誠則靈\n    (B)勤慎用兵，以誠為本\n    (C)慎可以醫惰，勤可以醫驕\n    (D)修身首重勤，次為慎，終為誠\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-019", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「65%的英國人承認壺裡的水裝太滿，其實他們通常只需要泡一杯茶。有人算\n出，使用電水壺一天額外產生的能源消耗，足以點亮英國一個晚上所有的路\n燈。」根據這段文字，可明確推論出下列何者？", "options": ["35%的英國人只喝冷水不喝熱茶", "至少65%的英國人意識到自己煮了過多的水", "英國多數的電水壺一次只能煮出一杯茶的水量", "點亮英國一整晚燈的電量相當於使用電水壺一天"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 19, "raw_text": "19. 「65%的英國人承認壺裡的水裝太滿，其實他們通常只需要泡一杯茶。有人算\n     出，使用電水壺一天額外產生的能源消耗，足以點亮英國一個晚上所有的路\n     燈。」根據這段文字，可明確推論出下列何者？\n     (A)35%的英國人只喝冷水不喝熱茶\n     (B)至少65%的英國人意識到自己煮了過多的水\n     (C)英國多數的電水壺一次只能煮出一杯茶的水量\n     (D)點亮英國一整晚燈的電量相當於使用電水壺一天\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-020", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "下列文句「」中的字，何者讀音正確？", "options": ["他對朋友的要求總是「慨」然應允：ㄍㄞˋ", "「囿」於成見，他一直排斥這項工作：ㄧㄡˋ", "警方追捕多年的通「緝」犯，終於在今日落網：ㄐㄧˊ", "這家公司處理消費糾紛的過程粗「糙」，引起民眾反彈：ㄗㄠˋ"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 20, "raw_text": "20. 下列文句「」中的字，何者讀音正確？\n    (A)他對朋友的要求總是「慨」然應允：ㄍㄞˋ\n    (B)「囿」於成見，他一直排斥這項工作：ㄧㄡˋ\n    (C)警方追捕多年的通「緝」犯，終於在今日落網：ㄐㄧˊ\n    (D)這家公司處理消費糾紛的過程粗「糙」，引起民眾反彈：ㄗㄠˋ\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-021", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "小淳參加王爺爺的壽宴，在會場聽到以下對話，哪一組用詞最為得體？", "options": ["王爺爺之子：「林先生、林太太，歡迎賢伉儷大駕光臨。」 林先生：「敝伉儷恭賀令堂生日快樂。」", "張先生：「王爺爺，祝您生日快樂。」 王爺爺：「小張，歡迎你光臨貴府。」", "李太太：「王大哥，看你們賢喬梓父慈子孝，令人好生羨慕！」 王爺爺之子：「託您的福。」", "王奶奶：「很榮幸內人我可以替您服務。」 陳太太：「不敢，麻煩王奶奶了。」"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21.   小淳參加王爺爺的壽宴，在會場聽到以下對話，哪一組用詞最為得體？\n      (A)王爺爺之子：「林先生、林太太，歡迎賢伉儷大駕光臨。」\n         林先生：「敝伉儷恭賀令堂生日快樂。」\n      (B)張先生：「王爺爺，祝您生日快樂。」\n         王爺爺：「小張，歡迎你光臨貴府。」\n      (C)李太太：「王大哥，看你們賢喬梓父慈子孝，令人好生羨慕！」\n         王爺爺之子：「託您的福。」\n      (D)王奶奶：「很榮幸內人我可以替您服務。」\n         陳太太：「不敢，麻煩王奶奶了。」\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-022", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「鳩摩羅什願凡所宣譯傳流後世，每云：『天竺國俗甚重文制，其宮商體韻以\n入弦為善，以歌嘆為貴。改梵為漢，失其藻蔚，雖得大意，殊隔文體。有似嚼\n飯與人，非徒失味，乃令嘔也。』」根據這段文字，下列何者最符合鳩摩羅什\n對譯經的看法？", "options": ["可因國情不同而修改內容", "首要關鍵在於音律的和諧", "應避免以華麗辭藻干擾文意", "保留原文形式之美並不容易"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 22, "raw_text": "22. 「鳩摩羅什願凡所宣譯傳流後世，每云：『天竺國俗甚重文制，其宮商體韻以\n    入弦為善，以歌嘆為貴。改梵為漢，失其藻蔚，雖得大意，殊隔文體。有似嚼\n    飯與人，非徒失味，乃令嘔也。』」根據這段文字，下列何者最符合鳩摩羅什\n    對譯經的看法？\n    (A)可因國情不同而修改內容\n    (B)首要關鍵在於音律的和諧\n    (C)應避免以華麗辭藻干擾文意\n    (D)保留原文形式之美並不容易\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-023", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "皮日休詠房、杜1詩云：「黃閣2三十年，清風一萬古。」凡言千古萬古\n者，皆是無窮之意，今下「一」字，便有所止矣。\n根據這則詩評，下列關於皮日休詩的敘述何者最恰當？", "options": ["用字遣詞多落入俗套", "數字對仗工整，可稱佳作   ", "詩句用字精確，傳誦千古   1.房、杜：指唐代名相房玄齡、杜如晦", "「一」字影響了詩句的意境  2.黃閣：宰相"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 23, "raw_text": "23.     皮日休詠房、杜1詩云：「黃閣2三十年，清風一萬古。」凡言千古萬古\n      者，皆是無窮之意，今下「一」字，便有所止矣。\n\n      根據這則詩評，下列關於皮日休詩的敘述何者最恰當？\n      (A)用字遣詞多落入俗套\n      (B)數字對仗工整，可稱佳作   \n      (C)詩句用字精確，傳誦千古   1.房、杜：指唐代名相房玄齡、杜如晦\n      (D)「一」字影響了詩句的意境  2.黃閣：宰相\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-024", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "某心理學家讓兩組學生看同一張人像，對第一組說：「他是罪大惡極的\n罪犯。」對第二組說：「他是一位科學家。」當請學生描述照片中的人時，\n第一組學生說：「深陷的雙眼顯現出他充滿仇恨，突出的下巴證明他在犯罪\n道路上頑強的決心。」第二組學生說：「深陷的雙眼顯現出他思想的深度，\n突出的下巴證明他在科學道路上堅強的鬥志。」\n這項實驗設計的目的，最可能是在印證下列何者？", "options": ["先入為主的成見，常會影響我們的判斷", "做任何事都要有決心與鬥志，才能成功", "昇華與墮落在一念之間，端看如何選擇", "看事情的角度因人而異，無絕對的是非"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 24, "raw_text": "24.     某心理學家讓兩組學生看同一張人像，對第一組說：「他是罪大惡極的\n      罪犯。」對第二組說：「他是一位科學家。」當請學生描述照片中的人時，\n      第一組學生說：「深陷的雙眼顯現出他充滿仇恨，突出的下巴證明他在犯罪\n      道路上頑強的決心。」第二組學生說：「深陷的雙眼顯現出他思想的深度，\n      突出的下巴證明他在科學道路上堅強的鬥志。」\n\n      這項實驗設計的目的，最可能是在印證下列何者？\n      (A)先入為主的成見，常會影響我們的判斷\n      (B)做任何事都要有決心與鬥志，才能成功\n      (C)昇華與墮落在一念之間，端看如何選擇\n      (D)看事情的角度因人而異，無絕對的是非\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-025", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "龍眼枝甚柔脆，熟時賃慣手1登採，恐其恣食，與約曰：「唱勿輟，輟則\n無薪。」樹枝扶疏，人坐綠蔭中，高低斷續，喁喁2弗已。遠聽之，頗足娛耳。\n土人謂之「唱龍眼」。\n根據這段文字，可明確得知下列何者？", "options": ["主人肯錄用沒有經驗的人            1.慣手：有經驗的人", "不諳歌唱的工人不予工資           2.喁喁：低語聲", "「唱龍眼」源自於主人防弊的手段", "採龍眼的工人喜在工作時彼此唱和"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 25, "raw_text": "25.\n        龍眼枝甚柔脆，熟時賃慣手1登採，恐其恣食，與約曰：「唱勿輟，輟則\n      無薪。」樹枝扶疏，人坐綠蔭中，高低斷續，喁喁2弗已。遠聽之，頗足娛耳。\n      土人謂之「唱龍眼」。\n\n      根據這段文字，可明確得知下列何者？\n      (A)主人肯錄用沒有經驗的人           \n                               1.慣手：有經驗的人\n      (B)不諳歌唱的工人不予工資           2.喁喁：低語聲\n      (C)「唱龍眼」源自於主人防弊的手段\n      (D)採龍眼的工人喜在工作時彼此唱和\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-026", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "下列文句，何者文意通暢、用詞最為恰當？", "options": ["在我軍堅守防線之下，敵軍難以越瑤池一步", "她性格豪邁直爽，英姿煥發，彷彿小家碧玉", "他成功的振興經濟，解民倒懸，獲得眾人愛戴", "教育小孩的方法必須剛烈並濟，才能達到效果"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 26, "raw_text": "26. 下列文句，何者文意通暢、用詞最為恰當？\n    (A)在我軍堅守防線之下，敵軍難以越瑤池一步\n    (B)她性格豪邁直爽，英姿煥發，彷彿小家碧玉\n    (C)他成功的振興經濟，解民倒懸，獲得眾人愛戴\n    (D)教育小孩的方法必須剛烈並濟，才能達到效果\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-027", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「客睡何曾著，秋天不肯明。入簾殘月影，高枕遠江聲。計拙無衣食，途窮仗\n友生1。老妻書數紙，應悉未歸情。」根據本詩，關於詩中主人翁的敘述，下\n列何者不正確？", "options": ["經濟拮据，生活困頓", "親友疏離，借貸無門  1.友生：朋友", "生計無著，徹夜難眠", "夫妻分離，兩地相思"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 27, "raw_text": "27. 「客睡何曾著，秋天不肯明。入簾殘月影，高枕遠江聲。計拙無衣食，途窮仗\n     友生1。老妻書數紙，應悉未歸情。」根據本詩，關於詩中主人翁的敘述，下\n     列何者不正確？\n     (A)經濟拮据，生活困頓    (B)親友疏離，借貸無門 \n                                  1.友生：朋友\n     (C)生計無著，徹夜難眠    (D)夫妻分離，兩地相思\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-109-chinese-028", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-109-chinese", "question_type": "single_choice", "question_text": "「以為攝影捕攫物象而加以複製便是寫實，是忽略了攝影和其他藝術共通的創\n作元素：主觀的選擇。一旦必須通過人的意識選擇安排而呈現，絕對的客觀\n便失去了意義。」這段文字的涵義與下列何者最接近？", "options": ["客觀的寫實是攝影和其他藝術共通的元素", "攝影藝術所追求的終極境界是絕對的客觀", "個人喜好不同，欣賞攝影作品的角度就不同", "攝影被視為創作，必然具有主觀意識的安排"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "17ed74d9cea4", "answer_pdf_sha1": "64e8d2b7d3a1", "flags": [], "parse_confidence": 1.0, "original_question_number": 28, "raw_text": "28. 「以為攝影捕攫物象而加以複製便是寫實，是忽略了攝影和其他藝術共通的創\n    作元素：主觀的選擇。一旦必須通過人的意識選擇安排而呈現，絕對的客觀\n    便失去了意義。」這段文字的涵義與下列何者最接近？\n    (A)客觀的寫實是攝影和其他藝術共通的元素\n    (B)攝影藝術所追求的終極境界是絕對的客觀\n    (C)個人喜好不同，欣賞攝影作品的角度就不同\n    (D)攝影被視為創作，必然具有主觀意識的安排\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
